b   = "oggbucket"

// The heartbeats in the path, in order
hbs = ["EWEST","DPWE","RWEST"]

// 1) Base: max lag per heartbeat per window
base =
  from(bucket: b)
    |> range(start: v.timeRangeStart, stop: v.timeRangeStop)
    |> filter(fn: (r) => r._measurement == "heartbeat-timings_heartbeat-lag")
    |> filter(fn: (r) => contains(value: r["heartbeat-name"], set: hbs))
    // per-thread -> per-window: keep each heartbeats max
    |> aggregateWindow(every: v.windowPeriod, fn: max, createEmpty: false)
    |> keep(columns: ["_time","_value","heartbeat-name"])

// 2) Pivot so each heartbeat is a column: EWEST, DPWE, RWEST
pivoted =
  base
    |> pivot(
        rowKey: ["_time"],
        columnKey: ["heartbeat-name"],
        valueColumn: "_value"
    )

// 3) Compute incremental lags and total
segments =
  pivoted
    |> map(fn: (r) => ({
        _time: r._time,

        // cumulative values (if missing, treat as 0)
        ew:   if exists r.EWEST then float(v: r.EWEST) else 0.0,
        dp:   if exists r.DPWE  then float(v: r.DPWE)  else 0.0,
        rw:   if exists r.RWEST then float(v: r.RWEST) else 0.0,

        // incremental lags (never negative)
        extract: 
          if exists r.EWEST then float(v: r.EWEST) else 0.0,

        routing:
          if exists r.DPWE and exists r.EWEST and float(v: r.DPWE) > float(v: r.EWEST)
          then float(v: r.DPWE) - float(v: r.EWEST)
          else 0.0,

        replicat:
          if exists r.RWEST and exists r.DPWE and float(v: r.RWEST) > float(v: r.DPWE)
          then float(v: r.RWEST) - float(v: r.DPWE)
          else 0.0,

        total:
          if exists r.RWEST then float(v: r.RWEST) else 0.0,
    }))

// 4) Turn the wide segments into 4 ordered series
extractSeries =
  segments
    |> map(fn: (r) => ({
        _time: r._time,
        _value: r.extract,
        _measurement: "1 Extract"
    }))
    |> group(columns: ["_measurement"])

routingSeries =
  segments
    |> map(fn: (r) => ({
        _time: r._time,
        _value: r.routing,
        _measurement: "2 Distribution Path"
    }))
    |> group(columns: ["_measurement"])

replicatSeries =
  segments
    |> map(fn: (r) => ({
        _time: r._time,
        _value: r.replicat,
        _measurement: "3 Replicat"
    }))
    |> group(columns: ["_measurement"])

totalSeries =
  segments
    |> map(fn: (r) => ({
        _time: r._time,
        _value: r.total,
        _measurement: "4 Total"
    }))
    |> group(columns: ["_measurement"])

// 5) Show Extract + Dist Path + Replicat + Total
union(tables: [extractSeries, routingSeries, replicatSeries, totalSeries])
  |> yield(name: "Incremental lag by role + Total")

